147→fn first_share_message_preview(snapshot: &ShareSnapshot) -> String {
148→    let mut out = String::new();
149→    for msg in &snapshot.messages {
150→        if msg.content.trim().is_empty() {
151→            continue;
152→        }
153→        if !out.is_empty() {
154→            out.push_str(" — ");
155→        }
156→        out.push_str(msg.content.trim());
157→        if out.len() >= 180 {
158→            break;
159→        }
160→    }
161→
162→    if out.is_empty() {
163→        "Shared conversation snapshot from Moltis".to_string()
164→    } else {
165→        truncate_for_meta(&out, 220)
166→    }
167→}
