193→pub(crate) fn human_share_time(ts_ms: u64) -> String {
194→    let millis = ts_ms.min(i64::MAX as u64) as i64;
195→    Utc.timestamp_millis_opt(millis)
196→        .single()
197→        .map(|utc| {
198→            utc.with_timezone(&Local)
199→                .format("%Y-%m-%d %H:%M")
200→                .to_string()
201→        })
202→        .unwrap_or_else(|| "1970-01-01 00:00".to_string())
203→}
