228→fn image_dimensions_from_data_url(data_url: &str) -> Option<(u32, u32)> {
229→    let (meta, body) = data_url.split_once(',')?;
230→    if !meta.starts_with("data:image/") || !meta.contains(";base64") {
231→        return None;
232→    }
233→    let bytes = base64::engine::general_purpose::STANDARD
234→        .decode(body.trim())
235→        .ok()?;
236→    let metadata = moltis_media::image_ops::get_image_metadata(&bytes).ok()?;
237→    Some((metadata.width, metadata.height))
238→}
