240→pub(crate) fn map_share_message_views(
241→    snapshot: &ShareSnapshot,
242→    identity: &moltis_config::ResolvedIdentity,
243→) -> Vec<ShareMessageView> {
244→    let user_label = share_user_label(identity);
245→    let assistant_label = share_assistant_label(identity);
246→
247→    snapshot
248→        .messages
249→        .iter()
250→        .filter_map(|msg| {
251→            let (role_class, role_label) = match msg.role {
252→                SharedMessageRole::User => ("user", user_label.clone()),
253→                SharedMessageRole::Assistant => ("assistant", assistant_label.clone()),
254→                SharedMessageRole::ToolResult => ("tool", "Tool".to_string()),
255→                SharedMessageRole::System | SharedMessageRole::Notice => return None,
256→            };
257→            let footer = match msg.role {
258→                SharedMessageRole::Assistant => match (&msg.provider, &msg.model) {
259→                    (Some(provider), Some(model)) => Some(format!("{provider} / {model}")),
260→                    (None, Some(model)) => Some(model.clone()),
261→                    (Some(provider), None) => Some(provider.clone()),
262→                    (None, None) => None,
263→                },
264→                SharedMessageRole::User
265→                | SharedMessageRole::ToolResult
266→                | SharedMessageRole::System
267→                | SharedMessageRole::Notice => None,
268→            };
269→            let (tool_state_class, tool_state_label, tool_state_badge_class) = match msg.role {
270→                SharedMessageRole::ToolResult => match msg.tool_success {
271→                    Some(true) => (Some("msg-tool-success"), Some("Success"), Some("ok")),
272→                    Some(false) => (Some("msg-tool-fail"), Some("Failed"), Some("fail")),
273→                    None => (None, None, None),
274→                },
275→                SharedMessageRole::User
276→                | SharedMessageRole::Assistant
277→                | SharedMessageRole::System
278→                | SharedMessageRole::Notice => (None, None, None),
279→            };
280→            let (is_exec_card, exec_card_class, exec_command) = match msg.role {
281→                SharedMessageRole::ToolResult => {
282→                    if msg.tool_name.as_deref() == Some("exec") {
283→                        let card_class = match msg.tool_success {
284→                            Some(true) => Some("exec-ok"),
285→                            Some(false) => Some("exec-err"),
286→                            None => None,
287→                        };
288→                        (true, card_class, msg.tool_command.clone())
289→                    } else {
290→                        (false, None, None)
291→                    }
292→                },
293→                SharedMessageRole::User
294→                | SharedMessageRole::Assistant
295→                | SharedMessageRole::System
296→                | SharedMessageRole::Notice => (false, None, None),
297→            };
298→            let (
299→                image_preview_data_url,
300→                image_link_data_url,
301→                image_preview_width,
302→                image_preview_height,
303→                image_has_dimensions,
304→            ) = if let Some(image) = msg.image.as_ref() {
305→                let preview = &image.preview;
306→                let link = image
307→                    .full
308→                    .as_ref()
309→                    .map_or_else(|| preview.data_url.clone(), |full| full.data_url.clone());
310→                (
311→                    Some(preview.data_url.clone()),
312→                    Some(link),
313→                    preview.width,
314→                    preview.height,
315→                    true,
316→                )
317→            } else if let Some(legacy_data_url) = msg.image_data_url.clone() {
318→                if let Some((width, height)) = image_dimensions_from_data_url(&legacy_data_url) {
319→                    (
320→                        Some(legacy_data_url.clone()),
321→                        Some(legacy_data_url),
322→                        width,
323→                        height,
324→                        true,
325→                    )
326→                } else {
327→                    (
328→                        Some(legacy_data_url.clone()),
329→                        Some(legacy_data_url),
330→                        0,
331→                        0,
332→                        false,
333→                    )
334→                }
335→            } else {
336→                (None, None, 0, 0, false)
337→            };
338→            Some(ShareMessageView {
339→                role_class,
340→                role_label,
341→                content: msg.content.clone(),
342→                reasoning: msg
343→                    .reasoning
344→                    .as_deref()
345→                    .map(str::trim)
346→                    .filter(|value| !value.is_empty())
347→                    .map(ToOwned::to_owned),
348→                audio_data_url: msg.audio_data_url.clone(),
349→                image_preview_data_url,
350→                image_link_data_url,
351→                image_preview_width,
352→                image_preview_height,
353→                image_has_dimensions,
354→                tool_state_class,
355→                tool_state_label,
356→                tool_state_badge_class,
357→                is_exec_card,
358→                exec_card_class,
359→                exec_command,
360→                map_link_google: msg
361→                    .map_links
362→                    .as_ref()
363→                    .and_then(|links| links.google_maps.clone()),
364→                map_link_apple: msg
365→                    .map_links
366→                    .as_ref()
367→                    .and_then(|links| links.apple_maps.clone()),
368→                map_link_openstreetmap: msg
369→                    .map_links
370→                    .as_ref()
371→                    .and_then(|links| links.openstreetmap.clone()),
372→                created_at_ms: msg.created_at,
373→                created_at_label: msg.created_at.map(human_share_time),
374→                footer,
375→            })
376→        })
377→        .collect()
378→}
