384→static SHARE_SOCIAL_BRAND_ICON_DATA_URL: std::sync::LazyLock<String> =
385→    std::sync::LazyLock::new(|| {
386→        let png_bytes = crate::assets::read_asset_bytes("icons/favicon-compact-512.png")
387→            .unwrap_or_else(|| {
