401→fn escape_svg_text(text: &str) -> String {
402→    text.replace('&', "&amp;")
403→        .replace('<', "&lt;")
404→        .replace('>', "&gt;")
405→        .replace('"', "&quot;")
406→        .replace('\'', "&#39;")
407→}
408→
409→fn normalize_share_social_text(text: &str) -> String {
410→    text.split_whitespace().collect::<Vec<_>>().join(" ")
411→}
412→
413→fn wrap_share_social_line(text: &str, max_chars: usize) -> Vec<String> {
414→    if max_chars == 0 {
415→        return vec![];
416→    }
417→
418→    let mut lines = Vec::new();
419→    let mut current = String::new();
420→    let mut current_len = 0usize;
421→
422→    for raw_word in text.split_whitespace() {
423→        let mut word = raw_word.to_string();
424→        let mut word_len = word.chars().count();
425→        if word_len > max_chars {
426→            word = truncate_for_meta(&word, max_chars.saturating_sub(1));
427→            word_len = word.chars().count();
428→        }
429→
430→        if current.is_empty() {
431→            current.push_str(&word);
432→            current_len = word_len;
433→            continue;
434→        }
435→
436→        if current_len + 1 + word_len <= max_chars {
437→            current.push(' ');
438→            current.push_str(&word);
439→            current_len += 1 + word_len;
440→            continue;
441→        }
442→
443→        lines.push(current);
444→        current = word;
445→        current_len = word_len;
446→    }
447→
448→    if !current.is_empty() {
449→        lines.push(current);
450→    }
451→
452→    lines
453→}
454→
455→fn build_share_social_text_lines(
456→    snapshot: &ShareSnapshot,
457→    identity: &moltis_config::ResolvedIdentity,
458→    max_chars: usize,
459→    max_lines: usize,
460→) -> Vec<String> {
461→    let user_label = share_user_label(identity);
462→    let assistant_label = share_assistant_label(identity);
463→    let mut lines = Vec::new();
464→    let mut truncated = false;
465→
466→    for msg in &snapshot.messages {
467→        let role = match msg.role {
468→            SharedMessageRole::User => user_label.as_str(),
469→            SharedMessageRole::Assistant => assistant_label.as_str(),
470→            SharedMessageRole::ToolResult => "Tool",
471→            SharedMessageRole::System | SharedMessageRole::Notice => continue,
472→        };
473→        let content = normalize_share_social_text(&msg.content);
474→        if content.is_empty() {
475→            continue;
476→        }
477→        let snippet = format!("{role}: {content}");
478→        let wrapped = wrap_share_social_line(&snippet, max_chars);
479→        for line in wrapped {
480→            if lines.len() >= max_lines {
481→                truncated = true;
482→                break;
483→            }
484→            lines.push(line);
485→        }
486→        if truncated {
487→            break;
488→        }
489→    }
490→
491→    if lines.is_empty() {
492→        lines.push("Shared conversation snapshot".to_string());
493→    } else if truncated && let Some(last) = lines.last_mut() {
494→        *last = truncate_for_meta(last, max_chars.saturating_sub(1));
495→    }
496→
497→    lines
498→}
