500→fn build_share_social_image_svg(
501→    snapshot: &ShareSnapshot,
502→    identity: &moltis_config::ResolvedIdentity,
503→) -> String {
504→    const MAX_CHARS_PER_LINE: usize = 64;
505→    const MAX_LINES: usize = 6;
506→    const WIDTH: usize = 1200;
507→    const HEIGHT: usize = 630;
508→
509→    let agent_name = identity_name(identity);
510→    let session_name = snapshot
511→        .session_label
512→        .as_deref()
513→        .map(str::trim)
514→        .filter(|value| !value.is_empty())
515→        .unwrap_or("Shared session");
516→    let title = truncate_for_meta(session_name, 90);
517→    let subtitle = format!(
518→        "{agent_name} • {} messages • {}",
519→        snapshot.cutoff_message_count,
520→        human_share_time(snapshot.created_at)
521→    );
522→    let lines = build_share_social_text_lines(snapshot, identity, MAX_CHARS_PER_LINE, MAX_LINES);
523→
524→    let mut conversation_lines = String::new();
525→    for (idx, line) in lines.iter().enumerate() {
526→        let y = 260 + idx * 48;
527→        conversation_lines.push_str(&format!(
528→            "<text x=\"78\" y=\"{y}\" fill=\"#e5e7eb\" font-size=\"29\" font-family=\"Inter, system-ui, sans-serif\">{}</text>",
529→            escape_svg_text(line)
530→        ));
531→    }
532→
533→    format!(
534→        "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"{WIDTH}\" height=\"{HEIGHT}\" viewBox=\"0 0 {WIDTH} {HEIGHT}\">\
535→<defs>\
536→  <linearGradient id=\"bg\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\">\
537→    <stop offset=\"0%\" stop-color=\"#0f172a\"/>\
538→    <stop offset=\"100%\" stop-color=\"#020617\"/>\
539→  </linearGradient>\
540→  <linearGradient id=\"accent\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\">\
541→    <stop offset=\"0%\" stop-color=\"#22c55e\"/>\
542→    <stop offset=\"100%\" stop-color=\"#16a34a\"/>\
543→  </linearGradient>\
544→  <radialGradient id=\"glow\" cx=\"0\" cy=\"0\" r=\"1\" gradientTransform=\"translate(1120 88) rotate(90) scale(240 300)\">\
545→    <stop offset=\"0%\" stop-color=\"#22c55e\" stop-opacity=\"0.2\"/>\
546→    <stop offset=\"100%\" stop-color=\"#22c55e\" stop-opacity=\"0\"/>\
547→  </radialGradient>\
548→  <clipPath id=\"brand-clip\">\
549→    <circle cx=\"1080\" cy=\"118\" r=\"50\"/>\
550→  </clipPath>\
551→</defs>\
552→<rect width=\"{WIDTH}\" height=\"{HEIGHT}\" fill=\"url(#bg)\"/>\
553→<rect width=\"{WIDTH}\" height=\"{HEIGHT}\" fill=\"url(#glow)\"/>\
554→<rect x=\"44\" y=\"40\" width=\"1112\" height=\"550\" rx=\"26\" fill=\"#0b1220\" fill-opacity=\"0.84\" stroke=\"#334155\"/>\
555→<rect x=\"74\" y=\"76\" width=\"8\" height=\"112\" rx=\"4\" fill=\"url(#accent)\"/>\
556→<circle cx=\"1080\" cy=\"118\" r=\"58\" fill=\"#0f172a\" stroke=\"#334155\" stroke-width=\"2\"/>\
557→<image x=\"1030\" y=\"68\" width=\"100\" height=\"100\" href=\"{}\" clip-path=\"url(#brand-clip)\"/>\
558→<text x=\"98\" y=\"120\" fill=\"#f8fafc\" font-size=\"46\" font-family=\"Inter, system-ui, sans-serif\" font-weight=\"700\">{}</text>\
559→<text x=\"98\" y=\"164\" fill=\"#93c5fd\" font-size=\"25\" font-family=\"Inter, system-ui, sans-serif\">{}</text>\
