562→<text x=\"1122\" y=\"584\" text-anchor=\"end\" fill=\"#9ca3af\" font-size=\"22\" font-family=\"Inter, system-ui, sans-serif\">By Moltis</text>\
563→</svg>",
564→        SHARE_SOCIAL_BRAND_ICON_DATA_URL.as_str(),
