 42→async fn start_auth_server_impl(
 43→    localhost_only: bool,
 44→    behind_proxy: bool,
 45→) -> (SocketAddr, Arc<CredentialStore>, Arc<GatewayState>) {
 46→    // Isolate each test process with its own config/data directory so
 47→    // concurrent nextest processes don't race on shared config files.
 48→    let tmp = tempfile::tempdir().unwrap();
 49→    moltis_config::set_config_dir(tmp.path().to_path_buf());
 50→    moltis_config::set_data_dir(tmp.path().to_path_buf());
 51→    // Leak the TempDir so it outlives the test (cleaned up on process exit).
 52→    std::mem::forget(tmp);
 53→
 54→    let pool = sqlx::SqlitePool::connect("sqlite::memory:").await.unwrap();
 55→    let auth_config = moltis_config::AuthConfig::default();
 56→    let cred_store = Arc::new(
 57→        CredentialStore::with_config(pool, &auth_config)
 58→            .await
 59→            .unwrap(),
 60→    );
 61→
 62→    let resolved_auth = auth::resolve_auth(None, None);
 63→    let services = GatewayServices::noop();
 64→    let state = GatewayState::with_options(
 65→        resolved_auth,
 66→        services,
 67→        None,
 68→        Some(Arc::clone(&cred_store)),
 69→        None, // pairing_store
 70→        localhost_only,
 71→        behind_proxy,
 72→        false,
 73→        None,
 74→        None,
 75→        18789,
 76→        false,
 77→        None,
 78→        None, // session_event_bus
 79→        #[cfg(feature = "metrics")]
 80→        None,
 81→        #[cfg(feature = "metrics")]
 82→        None,
 83→        #[cfg(feature = "vault")]
 84→        None,
 85→    );
 86→    let state_clone = Arc::clone(&state);
 87→    let methods = Arc::new(MethodRegistry::new());
 88→    #[cfg(feature = "push-notifications")]
 89→    let (router, app_state) = build_gateway_base(state, methods, None, None);
 90→    #[cfg(not(feature = "push-notifications"))]
 91→    let (router, app_state) = build_gateway_base(state, methods, None);
 92→
 93→    let router = router.merge(moltis_web::web_routes());
 94→    let app = finalize_gateway_app(router, app_state, false);
 95→
 96→    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
 97→    let addr = listener.local_addr().unwrap();
 98→    tokio::spawn(async move {
 99→        axum::serve(
100→            listener,
101→            app.into_make_service_with_connect_info::<SocketAddr>(),
102→        )
103→        .await
104→        .unwrap();
105→    });
106→    (addr, cred_store, state_clone)
107→}
