async fn start_auth_server_impl(
    localhost_only: bool,
    behind_proxy: bool,
) -> (SocketAddr, Arc<CredentialStore>, Arc<GatewayState>) {
    // 1. Setup: temp config/data dirs
    let tmp = tempfile::tempdir().unwrap();
    moltis_config::set_config_dir(tmp.path().to_path_buf());
    moltis_config::set_data_dir(tmp.path().to_path_buf());
    std::mem::forget(tmp); // Leak to outlive test

    // 2. Create in-memory SQLite pool
    let pool = sqlx::SqlitePool::connect("sqlite::memory:").await.unwrap();

    // 3. Create CredentialStore
    let auth_config = moltis_config::AuthConfig::default();
    let cred_store = Arc::new(
        CredentialStore::with_config(pool, &auth_config).await.unwrap(),
    );

    // 4. Resolve auth and create services
    let resolved_auth = auth::resolve_auth(None, None);
    let services = GatewayServices::noop(); // No-op services for testing

    // 5. Create GatewayState with options
    let state = GatewayState::with_options(
        resolved_auth,
        services,
        None, // sandbox_router
        Some(Arc::clone(&cred_store)),
        None, // pairing_store
        localhost_only,
        behind_proxy,
        false,
        None,
        None,
        18789, // port
        false,
        None,
        None, // session_event_bus
        #[cfg(feature = "metrics")] None,
        #[cfg(feature = "vault")] None,
    );

    // 6. Build gateway with routes
    let methods = Arc::new(MethodRegistry::new());
    let (router, app_state) = build_gateway_base(state, methods, None);
    let router = router.merge(moltis_web::web_routes());
    let app = finalize_gateway_app(router, app_state, false);

    // 7. Start server on ephemeral port
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    tokio::spawn(async move {
        axum::serve(listener, app.into_make_service_with_connect_info::<SocketAddr>())
            .await
            .unwrap();
    });
}
