// ── Onboarding auth protection tests ─────────────────────────────────────────

/// During setup (no password), a remote connection to /onboarding is
/// redirected to /setup-required — the auth gate must never redirect back
/// to /onboarding (which would cause an infinite 303 loop).
#[cfg(feature = "web-ui")]
#[tokio::test]
async fn onboarding_redirects_to_setup_required_for_remote() {
    let (addr, _store, _state) = start_proxied_server().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let resp = client
        .get(format!("http://{addr}/onboarding"))
        .send()
        .await
        .unwrap();

    // Remote setup-required must redirect to the setup-required page,
    // not loop back to /onboarding (#350).
    assert!(
        resp.status().is_redirection(),
        "remote /onboarding during setup should redirect"
    );
    let location = resp
        .headers()
        .get("location")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    assert_eq!(
        location, "/setup-required",
        "remote /onboarding during setup must redirect to /setup-required"
    );
}

/// After setup is complete, /onboarding requires authentication — an
/// unauthenticated remote request must be redirected to /login.
#[cfg(feature = "web-ui")]
#[tokio::test]
async fn onboarding_requires_auth_after_setup() {
    let (addr, store, _state) = start_proxied_server().await;
    store.set_initial_password("testpass123").await.unwrap();

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let resp = client
        .get(format!("http://{addr}/onboarding"))
        .send()
        .await
        .unwrap();

    // After setup, unauthenticated request to /onboarding must redirect to /login.
    assert!(
        resp.status().is_redirection(),
        "/onboarding should redirect when setup is complete and request is unauthenticated"
    );
    let location = resp
        .headers()
        .get("location")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    assert_eq!(
        location, "/login",
        "/onboarding should redirect to /login after setup, not {location}"
    );
}

